import type { UmbRoutableWorkspaceContext, UmbSubmittableWorkspaceContext } from "@umbraco-cms/backoffice/workspace";
import { UmbSubmittableWorkspaceContextBase, UmbWorkspaceIsNewRedirectController } from "@umbraco-cms/backoffice/workspace";
import type { UmbControllerHostElement } from "@umbraco-cms/backoffice/controller-api";
import { UmbObjectState } from "@umbraco-cms/backoffice/observable-api";
import { FieldTypeService, type Field, type FieldsetContainer, type FormDesign, type Page } from "@umbraco-forms/generated";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import { UmbRequestReloadChildrenOfEntityEvent, UmbRequestReloadStructureForEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { UmbPropertyEditorConfigCollection } from "@umbraco-cms/backoffice/property-editor";
import { GUID_EMPTY } from "@umbraco-forms/entities";
import { FORMS_FORM_ENTITY_TYPE } from "../entities.js";
import { FormsFormDetailRepository } from "../repository/index.js";
import { FormsPrevalueSourceCollectionRepository, FormsPrevalueSourceDetailRepository } from "../../prevaluesources/repository/index.js";
import { FormsFieldTypeDetailRepository } from "../../provider-types/field-types/repository/detail/index.js";
import { FormsWorkflowTypeDetailRepository } from "../../provider-types/workflow-types/repository/detail/index.js";
import type { FieldPrevalueDetail, ActionType, LogicType, OperatorType } from "../types.js";
import FormsWorkspaceEditorElement from "./form-workspace-editor.element.js";
import { FORM_WORKSPACE_ALIAS } from "./manifests.js";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import { UmbLocalizationController } from "@umbraco-cms/backoffice/localization-api";

export class FormsFormWorkspaceContext
  extends UmbSubmittableWorkspaceContextBase<FormDesign>
  implements UmbSubmittableWorkspaceContext, UmbRoutableWorkspaceContext
{
  public readonly formRepository = new FormsFormDetailRepository(this);
  public readonly fieldTypeRepository = new FormsFieldTypeDetailRepository(this);
  public readonly workflowTypeRepository = new FormsWorkflowTypeDetailRepository(this);
  public readonly prevalueSourceCollectionRepository = new FormsPrevalueSourceCollectionRepository(this);

  #parent?: { entityType: string; unique: string | null };
  #data = new UmbObjectState<FormDesign | undefined>(undefined);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  #getDataPromise?: Promise<any>;

  readonly data = this.#data.asObservable();
  readonly unique = this.#data.asObservablePart((data) => data?.unique);
  readonly name = this.#data.asObservablePart((data) => data?.name);
  readonly id = this.#data.asObservablePart((data) => data?.unique);

  constructor(host: UmbControllerHostElement) {
    super(host, FORM_WORKSPACE_ALIAS);

    this.routes.setRoutes([
      {
        path: "create/parent/:entityType/:parentUnique",
        component: FormsWorkspaceEditorElement,
        setup: this.#createOnWorkspaceContext,
      },
      {
        path: "createFromTemplate/parent/:entityType/:parentUnique/:template",
        component: FormsWorkspaceEditorElement,
        setup: this.#createOnWorkspaceContext,
      },
      {
        path: "edit/:unique",
        component: FormsWorkspaceEditorElement,
        setup: (_component, info) => {
          const unique = info.match.params.unique;
          this.load(unique);
        },
      },
    ]);
  }

  #createOnWorkspaceContext = async (_component, info) => {
    const parentEntityType = info.match.params.entityType;
    const parentUnique = info.match.params.parentUnique === 'null' ? null : info.match.params.parentUnique;
    const template = info.match.params.template;
    await this.create({ entityType: parentEntityType, unique: parentUnique }, template);
  };

  async load(id: string) {
    this.#getDataPromise = this.formRepository?.requestByUnique(id);
    const { data } = await this.#getDataPromise;

    if (data) {
      this.setIsNew(false);
      this.#data.update(data);
    }
  }

  async create(parent: { entityType: string; unique: string | null }, template: string | null) {
    this.#parent = parent;
    const scaffold = await this.formRepository.requestFormScaffold(template || "");

    let data = scaffold.data!.data;

    if (!data) throw new Error("Form design data is missing");

    data.folderId = parent.unique;
    if (this.modalContext) {
      data = { ...data, ...this.modalContext.data.preset };
    }
    this.setIsNew(true);
    this.#data.setValue(data);
    return { data };
  }

  async submit(): Promise<void> {
    if (!this.#data.value) return;
    if (!this.#data.value.unique) return;

    if (this.#data.value.name.trim().length === 0) {
      const notificationContext = await this.getContext(
        UMB_NOTIFICATION_CONTEXT
      );
      const localize = new UmbLocalizationController(this);
      notificationContext.peek("danger", {
        data: { message: localize.term("formEdit_noNameForForm") },
      });
      return;
    }

    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);

    if (this.getIsNew()) {
      if (!this.#parent) throw new Error('Parent is not set');
      await this.formRepository?.create(this.#data.value, this.#parent.unique);

      const event = new UmbRequestReloadChildrenOfEntityEvent({
        entityType: this.#parent.entityType,
        unique: this.#parent.unique,
      });
      eventContext.dispatchEvent(event);
      this.setIsNew(false);
    } else {
      await this.formRepository?.save(this.#data.value);

      const event = new UmbRequestReloadStructureForEntityEvent({
        unique: this.getUnique()!,
        entityType: this.getEntityType(),
      });
      eventContext.dispatchEvent(event);
    }
  }

  async loadFieldType(id: string) {
    const { data } = await this.fieldTypeRepository.requestByUnique(id);
    return data;
  }

  async loadWorkflowType(id: string) {
    const { data } = await this.workflowTypeRepository.requestByUnique(id);
    return data;
  }

  async loadValidationPatterns() {
    const { data } = await this.fieldTypeRepository.requestValidationPatterns();
    return data;
  }

  async loadPrevalueSources() {
    const { data } = await this.prevalueSourceCollectionRepository.requestCollection({});
    return data?.items;
  }

  getData() {
    return this.#data.getValue();
  }

  getUnique() {
    return this.getData()?.unique || '';
  }

  getEntityType(): string {
    return FORMS_FORM_ENTITY_TYPE;
  }

  getName() {
    return this.#data.getValue()?.name;
  }

  setName(name: string) {
    this.#data.update({ name });
  }

  setFormProperty(alias: string, value: any) {
    this.#data.update({ [alias]: value });
  }

  getFormProperty(alias: string) {
    return this.getData()?.[alias];
  }

  setPageProperty(pageIndex: number, alias: string, value: any) {
    const pages = this.#data.value?.pages.map((p, i) => ({
      ...p,
      ...(i === pageIndex && {
        [alias]: value
      })
    }));
    this.setFormProperty("pages", pages);
  }

  setFieldsetProperty(pageIndex: number, fieldsetIndex: number, alias: string, value: any) {
    const fieldSetsForPage = this.#data.value?.pages[pageIndex].fieldSets.map((fs, i) => ({
      ...fs,
      ...(i === fieldsetIndex && {
        [alias]: value
      })
    }));
    this.setPageProperty(pageIndex, "fieldSets", fieldSetsForPage);
  }

  setContainerProperty(pageIndex: number, fieldsetIndex: number, containerIndex: number, alias: string, value: any) {
    const containersForFieldSet = this.#data.value?.pages[pageIndex].fieldSets[fieldsetIndex].containers.map((c, i) => ({
      ...c,
      ...(i === containerIndex && {
        [alias]: value
      })
    }));
    this.setFieldsetProperty(pageIndex, fieldsetIndex, "containers", containersForFieldSet);
  }

  setFieldProperty(pageIndex: number, fieldsetIndex: number, containerIndex: number, fieldIndex: number, alias: string, value: any) {
    const fieldsForContainer = this.#data.value?.pages[pageIndex].fieldSets[fieldsetIndex].containers[containerIndex].fields.map((f, i) => ({
      ...f,
      ...(i === fieldIndex && {
        [alias]: value
      })
    }));
    this.setContainerProperty(pageIndex, fieldsetIndex, containerIndex, "fields", fieldsForContainer);
  }

  setWorkflowProperty(collectionName: string, index: number, alias: string, value: any) {
    const formWorkflows = structuredClone(this.#data.value?.formWorkflows);
    if (formWorkflows) {
      formWorkflows[collectionName][index][alias] = value;
      this.setFormProperty("formWorkflows", formWorkflows);
    }
  }

  moveFieldSet(currentPageIndex: number, currentFieldsetIndex: number, newPageIndex: number) {
    if (newPageIndex === currentPageIndex) return;
    const pages = structuredClone(this.#data.value?.pages);
    if (pages) {
      const currentPage = pages[currentPageIndex];
      const fieldSet = currentPage.fieldSets.splice(currentFieldsetIndex, 1)[0];
      const newPage = pages[newPageIndex];
      newPage.fieldSets.push(fieldSet);
      this.setFormProperty("pages", pages);
    }
  }

  moveField(fieldId: string, currentIndexPath: string, newIndexPath: string) {
    if (currentIndexPath === newIndexPath) return;

    const pages = structuredClone(this.#data.value?.pages);
    if (pages) {
      const currentContainer = this.#getContainerFromIndexPath(pages, currentIndexPath);
      const newContainer = this.#getContainerFromIndexPath(pages, newIndexPath);

      const fieldIndex = currentContainer.fields.findIndex(f => f.id == fieldId);
      const field = currentContainer.fields.splice(fieldIndex, 1)[0];
      newContainer.fields.push(field);
      this.setFormProperty("pages", pages);
    }
  }

  moveWorkflow(workflowIndex: number, fromCollectionName: string, toCollectionName: string) {
    if (!this.#data.value) return;
    const workflows = structuredClone(this.#data.value.formWorkflows);
    const fromCollection = workflows[fromCollectionName];
    const workflow = fromCollection.splice(workflowIndex, 1)[0];
    const toCollection = workflows[toCollectionName];
    toCollection.push(workflow);
    this.setFormProperty("formWorkflows", workflows);
  }

  #getContainerFromIndexPath(pages: Array<Page>, path: string) {
    const pathParts = path.split('_').map(s => parseInt(s));
    return pages[pathParts[0]].fieldSets[pathParts[1]].containers[pathParts[2]];
  }

  getAllPages() {
    const form = this.getData();
    if (!form) return [];

    const pages: Array<Page> = [];
    form.pages.forEach(p => {
      pages.push(p);
    });

    return pages;
  }

  getAllContainers() {
    const form = this.getData();
    if (!form) return [];

    const containers: Array<FieldsetContainer> = [];
    form.pages.forEach(p => {
      p.fieldSets.forEach(fs => {
        fs.containers.forEach(c => {
          containers.push(c);
        })
      })
    });

    return containers;
  }

  getAllFields() {
    const containers = this.getAllContainers();

    const fields: Array<Field> = [];
    containers.forEach(c => {
      c.fields.forEach(f => {
        fields.push(f);
      })
    });

    return fields;
  }

  getAllFieldAliases() {
    return this.getAllFields().map(f => f.alias);
  }

  getFieldsWithPrevalues(): Array<FieldPrevalueDetail> {
    const allFields = this.getAllFields();
    const fieldsWithPrevalues = allFields.filter(f => f.preValues.length > 0 || f.prevalueSourceId !== GUID_EMPTY);
    return fieldsWithPrevalues.map(f => {
      return {
        id: f.id,
        prevalues: f.preValues,
        prevalueSourceId: f.prevalueSourceId
      }
    });
  }

  getContainerIndexPathForField(id: string) {
    const form = this.getData();
    if (!form) return "";

    for (let p = 0; p < form.pages.length; p++) {
      const page = form.pages[p];
      for (let fs = 0; fs < page.fieldSets.length; fs++) {
        const fieldset = page.fieldSets[fs];
        for (let c = 0; c < fieldset.containers.length; c++) {
          const container = fieldset.containers[c];
          for (let f = 0; f < container.fields.length; f++) {
            const fieldSetField = container.fields[f];
            if (fieldSetField.id === id) {
              return p + "_" + fs + "_" + c;
            }
          }
        }
      }
    }

    return "";
  }

  getConditionActionTypes: Array<ActionType> = [{
    name: "Show",
    value: "Show"
  }, {
    name: "Hide",
    value: "Hide"
  }];

  getConditionLogicTypes: Array<LogicType> = [{
    name: "all",
    value: "All"
  }, {
    name: "any",
    value: "Any"
  }];

  getConditionOperators: Array<OperatorType> = [{
    name: "is",
    value: "Is"
  }, {
    name: "is not",
    value: "IsNot"
  }, {
    name: "is greater than",
    value: "GreaterThen"
  }, {
    name: "is less than",
    value: "LessThen"
  }, {
    name: "contains (case-sensitive)",
    value: "Contains"
  },
  {
    name: "contains (case-insensitive)",
    value: "ContainsIgnoreCase",
  },
  {
    name: "starts with (case-sensitive)",
    value: "StartsWith"
  },
  {
    name: "starts with (case-insensitive)",
    value: "StartsWithIgnoreCase"
  },
  {
    name: "ends with",
    value: "EndsWith"
  },
  {
    name: "ends with (case-insensitive)",
    value: "EndsWithIgnoreCase"
  },
  {
    name: "does not contain (case-sensitive)",
    value: "NotContains"
  },
  {
    name: "does not contain (case-insensitive)",
    value: "NotContainsIgnoreCase"
  },
  {
    name: "does not start with (case-sensitive)",
    value: "NotStartsWith"
  },
  {
    name: "does not start with (case-insensitive)",
    value: "NotStartsWithIgnoreCase"
  },
  {
    name: "does not end with (case-sensitive)",
    value: "NotEndsWith"
  },
  {
    name: "does not end with (case-insensitive)",
    value: "NotEndsWithIgnoreCase"
  }];

  async getRichTextConfiguration() {
    const { data } = await tryExecuteAndNotify(
      this,
      FieldTypeService.getFieldTypeRichtextDatatype(),
    );

    const config: UmbPropertyEditorConfigCollection = new UmbPropertyEditorConfigCollection([]);
    config.push({
      alias: "maxImageSize",
      value: data.configurationData.maxImageSize,
    });
    config.push({
      alias: "overlaySize",
      value: data.configurationData.overlaySize,
    });
    config.push({
      alias: "toolbar",
      value: data.configurationData.toolbar,
    });
    config.push({
      alias: "extensions",
      value: data.configurationData.extensions,
    });
    return config;
  }

  destroy() {
    this.#data.destroy();
    super.destroy();
  }
}

export const api = FormsFormWorkspaceContext;
